def update_edge_distance(edge_distance: np.ndarray, local_opt_tour: np.ndarray,
                          edge_n_used: np.ndarray) -> np.ndarray:
    n = edge_distance.shape[0]
    updated = edge_distance.copy()

    # Identify edges in the current local optimum
    tour_edges = set()
    for i in range(n):
        u = local_opt_tour[i]
        v = local_opt_tour[(i + 1) % n]
        if u < v:
            tour_edges.add((u, v))
        else:
            tour_edges.add((v, u))

    max_dist = edge_distance.max()
    penalty_factor = 0.3 * max_dist / (n + 1)
    reward_factor = 0.1 * max_dist / (n + 1)

    for i in range(n):
        for j in range(i + 1, n):
            if (i, j) in tour_edges:
                # Penalize edges in the tour
                penalty = penalty_factor * (1 + edge_n_used[i, j])
                updated[i, j] += penalty
                updated[j, i] += penalty
            else:
                # Reward short edges not in tour
                if edge_distance[i, j] < max_dist * 0.5:
                    reward = reward_factor * (1 + edge_n_used[i, j])
                    updated[i, j] = max(0, updated[i, j] - reward)
                    updated[j, i] = updated[i, j]

    return updated
